"use client";

import { useLayoutEffect, useMemo, useRef, useState } from "react";

type StageKey = "acquire" | "build" | "contain";
type StageColor = "blue" | "green" | "orange";
type StatusKey = "active" | "planned" | "paused";

type Segment = {
  id: string;
  label: string;
  value: string;
  status: StatusKey;
};

type Condition = {
  id: string;
  label: string;
  value: string;
  segments: Segment[];
};

type StageData = {
  key: StageKey;
  label: string;
  subtitle: string;
  total: string;
  color: StageColor;
  conditions: Condition[];
};

type Connector = {
  from: string;
  to: string;
  color: StageColor;
};

