const statusLabelMap: Record<StatusKey, string> = {
  active: "Active",
  planned: "Planned",
  paused: "Paused",
};

const colorStrokeMap: Record<StageColor, string> = {
  blue: "#8CA5C3",
  green: "#8FC3A1",
  orange: "#E9BE8C",
};

function makePath(x1: number, y1: number, x2: number, y2: number) {
  const curve = Math.max(32, Math.abs(x2 - x1) * 0.38);
  return `M ${x1} ${y1} C ${x1 + curve} ${y1}, ${x2 - curve} ${y2}, ${x2} ${y2}`;
}

export function OverviewTree() {
  const [activeStage, setActiveStage] = useState<StageKey>("acquire");
  const [paths, setPaths] = useState<Array<{ id: string; d: string; color: StageColor }>>([]);
  const canvasRef = useRef<HTMLDivElement | null>(null);
  const nodeRefs = useRef<Record<string, HTMLDivElement | null>>({});

  const stage = treeData[activeStage];

  const connectors = useMemo<Connector[]>(() => {
    const branchConnectors = stage.conditions.flatMap((condition) =>
      condition.segments.map((segment) => ({
        from: `condition-${condition.id}`,
        to: `segment-${segment.id}`,
        color: stage.color,
      })),
    );

    return [
      ...stage.conditions.map((condition) => ({
        from: "root",
        to: `condition-${condition.id}`,
        color: stage.color,
      })),
      ...branchConnectors,
    ];
  }, [stage]);

  useLayoutEffect(() => {
    const updatePaths = () => {
      const canvas = canvasRef.current;
      if (!canvas) {
        return;
      }

      const bounds = canvas.getBoundingClientRect();
      const nextPaths = connectors
        .map((connector) => {
          const fromNode = nodeRefs.current[connector.from];
          const toNode = nodeRefs.current[connector.to];
          if (!fromNode || !toNode) {
            return null;
          }

          const fromBounds = fromNode.getBoundingClientRect();
          const toBounds = toNode.getBoundingClientRect();

          const x1 = fromBounds.right - bounds.left;
          const y1 = fromBounds.top - bounds.top + fromBounds.height / 2;
          const x2 = toBounds.left - bounds.left;
          const y2 = toBounds.top - bounds.top + toBounds.height / 2;

          return {
            id: `${connector.from}-${connector.to}`,
            d: makePath(x1, y1, x2, y2),
            color: connector.color,
          };
        })
        .filter((item): item is { id: string; d: string; color: StageColor } => Boolean(item));

      setPaths(nextPaths);
    };

    updatePaths();

    const resizeObserver = typeof ResizeObserver !== "undefined" ? new ResizeObserver(updatePaths) : null;
    if (resizeObserver && canvasRef.current) {
      resizeObserver.observe(canvasRef.current);
    }

    window.addEventListener("resize", updatePaths);

    return () => {
      resizeObserver?.disconnect();
      window.removeEventListener("resize", updatePaths);
    };
  }, [connectors, stage]);

  return (
    <div className="overviewTree" ref={canvasRef}>
      <svg className="overviewTreeSvg" aria-hidden="true">
        {paths.map((path) => (
          <path
            key={path.id}
            d={path.d}
            className={`overviewTreePath ${path.color}`}
            vectorEffect="non-scaling-stroke"
          />
        ))}
      </svg>

      <div className="overviewTreeHeaders">
        <span>CONDITION</span>
        <span>PATIENT SEGMENTS</span>
        <span>STATUS</span>
      </div>

      <div className="overviewTreeBody">
        <aside className="overviewTreeStages">
          {Object.values(treeData).map((item) => {
            const isActive = item.key === activeStage;
            return (
              <button
                key={item.key}
                type="button"
                className={`overviewTreeStageButton ${item.color} ${isActive ? "active" : ""}`}
                onClick={() => setActiveStage(item.key)}
              >
                <strong>{item.label}</strong>
                <span>{item.subtitle}</span>
              </button>
            );
          })}
        </aside>

        <div className="overviewTreeSelectedWrap">
          <div
            ref={(node) => {
              nodeRefs.current.root = node;
            }}
            className={`overviewTreeSelected ${stage.color}`}
          >
            <strong>{stage.label.toUpperCase()}</strong>
            <span>{stage.total}</span>
          </div>
        </div>

        <div className="overviewTreeColumns">
          <div className="overviewTreeConditionColumn">
            {stage.conditions.map((condition) => (
              <div key={condition.id} className="overviewTreeBranchRow">
                <div
                  ref={(node) => {
                    nodeRefs.current[`condition-${condition.id}`] = node;
                  }}
                  className={`overviewTreeBox overviewTreeCondition ${stage.color}`}
                >
                  <span>{condition.label}</span>
                  <strong>{condition.value}</strong>
                </div>
              </div>
            ))}
          </div>

          <div className="overviewTreeSegmentsColumn">
            {stage.conditions.map((condition) => (
              <div key={condition.id} className="overviewTreeSegmentStack">
                {condition.segments.map((segment) => (
                  <div key={segment.id} className="overviewTreeSegmentRow">
                    <div
                      ref={(node) => {
                        nodeRefs.current[`segment-${segment.id}`] = node;
                      }}
                      className={`overviewTreeBox overviewTreeSegment ${stage.color}`}
                    >
                      <span>{segment.label}</span>
                      <strong>{segment.value}</strong>
                    </div>
                    <span className={`overviewTreeStatus ${segment.status}`}>{statusLabelMap[segment.status]}</span>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
