"use client";

import { useId } from "react";

import {
  CartesianGrid,
  Cell,
  Funnel,
  FunnelChart,
  LabelList,
  Pie,
  PieChart,
  ResponsiveContainer,
  Sankey,
  Scatter,
  ScatterChart,
  Tooltip,
  XAxis,
  YAxis,
  ZAxis,
} from "recharts";

type DonutDatum = {
  label: string;
  pct: number;
  color: string;
  value: string;
};

function parseCompactAmount(raw: string) {
  const match = raw.replace(/,/g, "").match(/(\d+(?:\.\d+)?)\s*([KMB])?/i);
  if (!match) {
    return 0;
  }

  const base = Number(match[1]);
  const suffix = (match[2] ?? "").toUpperCase();

  if (suffix === "B") {
    return base * 1_000_000_000;
  }
  if (suffix === "M") {
    return base * 1_000_000;
  }
  if (suffix === "K") {
    return base * 1_000;
  }

  return base;
}

function formatCompactAmount(value: number) {
  if (value >= 1_000_000_000) {
    return `${(value / 1_000_000_000).toFixed(value >= 10_000_000_000 ? 0 : 1).replace(/\.0$/, "")}B`;
  }
  if (value >= 1_000_000) {
    return `${(value / 1_000_000).toFixed(value >= 10_000_000 ? 0 : 1).replace(/\.0$/, "")}M`;
  }
  if (value >= 1_000) {
    return `${(value / 1_000).toFixed(value >= 10_000 ? 0 : 1).replace(/\.0$/, "")}K`;
  }
  return `${Math.round(value)}`;
}

type BubbleDatum = {
  label: string;
  value: number;
  color: string;
  x: number;
  y: number;
  size: number;
};

type FunnelDatum = {
  label: string;
  count: string;
  leftNote: string;
  rightNote: string;
  revenue: string;
  width: number;
  fill?: string;
};

function BubbleTooltip({ active, payload }: { active?: boolean; payload?: Array<{ payload: BubbleDatum }> }) {
  if (!active || !payload?.length) {
    return null;
  }

  const point = payload[0].payload;

  return (
    <div className="subConditionChartTooltip">
      <strong>{point.label}</strong>
      <span>{point.value}% conversion</span>
    </div>
  );
}

function BubbleShape(props: { cx?: number; cy?: number; payload?: BubbleDatum }) {
  const { cx = 0, cy = 0, payload } = props;

  if (!payload) {
    return null;
  }

  const radius = Math.max(payload.size / 3.2, 28);

  return (
    <g>
      <circle cx={cx} cy={cy} r={radius} fill={`${payload.color}24`} stroke={payload.color} strokeWidth={2} />
      <text x={cx} y={cy + 6} textAnchor="middle" fill={payload.color} fontSize="16" fontWeight="700">
        {payload.value}%
      </text>
    </g>
  );
}

function FunnelTooltip({ active, payload }: { active?: boolean; payload?: Array<{ payload: FunnelDatum }> }) {
  if (!active || !payload?.length) {
    return null;
  }

  const point = payload[0].payload;

  return (
    <div className="subConditionChartTooltip">
      <strong>{point.label}</strong>
      <span>{point.count} patients</span>
      <span>{point.revenue} incremental revenue</span>
    </div>
  );
}

function FunnelCenterLabel(props: {
  viewBox?: { x?: number; y?: number; width?: number; height?: number };
  value?: string;
  payload?: FunnelDatum & { labelText?: string };
}) {
  const { viewBox, payload } = props;

  if (!viewBox || !payload) {
    return null;
  }

  const x = (viewBox.x ?? 0) + (viewBox.width ?? 0) / 2;
  const y = (viewBox.y ?? 0) + (viewBox.height ?? 0) / 2;

  return (
    <text x={x} y={y + 4} textAnchor="middle" fill="#35515f" fontSize="12" fontWeight="700">
      {payload.label} · {payload.count}
    </text>
  );
}

function SankeyTooltip({
  active,
  payload,
}: {
  active?: boolean;
  payload?: Array<{ payload?: { sourceLabel?: string; targetLabel?: string; value?: number } }>;
}) {
  const point = payload?.[0]?.payload;

  if (!active || !point) {
    return null;
  }

  return (
    <div className="subConditionChartTooltip">
      <strong>
        {point.sourceLabel} to {point.targetLabel}
      </strong>
      <span>{formatCompactAmount(point.value ?? 0)} patients</span>
    </div>
  );
}

export function ExportLineChart({
  values,
  max,
  color = "#2563EB",
  area = false,
  width = 280,
  height = 140,
  labels,
  showDots = true,
}: {
  values: number[];
  max: number;
  color?: string;
  area?: boolean;
  width?: number;
  height?: number;
  labels?: string[];
  showDots?: boolean;
}) {
  const gradientId = useId().replace(/:/g, "");
  const p = 20;
  const x = (i: number) => p + (i / Math.max(values.length - 1, 1)) * (width - p * 2);
  const y = (v: number) => height - p - (v / max) * (height - p * 2);
  const path = values.map((v, i) => `${i ? "L" : "M"}${x(i)} ${y(v)}`).join(" ");
  const areaPath = `${path} L ${x(values.length - 1)} ${height - p} L ${x(0)} ${height - p} Z`;

  return (
    <svg className="linechart" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      <defs>
        <linearGradient id={`lineArea-${gradientId}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.34" />
          <stop offset="58%" stopColor={color} stopOpacity="0.12" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      {[0, 1, 2, 3].map((i) => (
        <line
          key={i}
          className="grid-line"
          x1={p}
          y1={p + (i * (height - p * 2)) / 3}
          x2={width - p}
          y2={p + (i * (height - p * 2)) / 3}
        />
      ))}
      {area ? <path d={areaPath} fill={`url(#lineArea-${gradientId})`} /> : null}
      <path d={path} fill="none" stroke={color} strokeWidth="2" />
      {showDots
        ? values.map((v, i) => <circle key={i} cx={x(i)} cy={y(v)} r="2.5" fill={color} />)
        : null}
      {labels?.map((label, i) => (
        <text key={label} className="tick" x={x(i)} y={height - 5} textAnchor="middle">
          {label}
        </text>
      ))}
    </svg>
  );
}

export function ExportMultiLineChart({
  series,
  labels,
  colors,
  width = 280,
  height = 140,
}: {
  series: number[][];
  labels: string[];
  colors: string[];
  width?: number;
  height?: number;
}) {
  const gradientSeed = useId().replace(/:/g, "");
  const p = 20;
  const maxY = Math.max(...series.flat(), 0) + 10;
  const x = (i: number) => p + (i / Math.max(labels.length - 1, 1)) * (width - p * 2);
  const y = (v: number) => height - p - (v / maxY) * (height - p * 2);
  return (
    <svg className="linechart" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      <defs>
        {colors.map((color, index) => (
          <linearGradient key={color + index} id={`multiLineArea-${gradientSeed}-${index}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={color} stopOpacity="0.34" />
            <stop offset="58%" stopColor={color} stopOpacity="0.12" />
            <stop offset="100%" stopColor={color} stopOpacity="0" />
          </linearGradient>
        ))}
      </defs>
      {[0, 1, 2, 3].map((i) => (
        <line
          key={i}
          className="grid-line"
          x1={p}
          y1={p + (i * (height - p * 2)) / 3}
          x2={width - p}
          y2={p + (i * (height - p * 2)) / 3}
        />
      ))}
      {series.map((row, rowIndex) => {
        const d = row.map((v, i) => `${i ? "L" : "M"}${x(i)} ${y(v)}`).join(" ");
        const areaD = `${d} L ${x(row.length - 1)} ${height - p} L ${x(0)} ${height - p} Z`;
        return (
          <g key={rowIndex}>
            <path d={areaD} fill={`url(#multiLineArea-${gradientSeed}-${rowIndex})`} />
            <path d={d} fill="none" stroke={colors[rowIndex]} strokeWidth="2" />
          </g>
        );
      })}
      {labels.map((label, i) => (
        <text key={label} className="tick" x={x(i)} y={height - 5} textAnchor="middle">
          {label}
        </text>
      ))}
    </svg>
  );
}

export function ExportBarValueChart({
  values,
  labels,
  color = "#86EFAC",
  textColor = "#16A34A",
  max,
}: {
  values: number[];
  labels: string[];
  color?: string;
  textColor?: string;
  max: number;
}) {
  const width = 280;
  const height = 140;
  const p = 20;
  const barW = (width - p * 2) / values.length - 6;
  return (
    <svg className="linechart" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      {[0, 1, 2, 3].map((i) => (
        <line
          key={i}
          className="grid-line"
          x1={p}
          y1={p + (i * (height - p * 2)) / 3}
          x2={width - p}
          y2={p + (i * (height - p * 2)) / 3}
        />
      ))}
      {values.map((v, i) => {
        const bx = p + i * ((width - p * 2) / values.length) + 3;
        const by = height - p - (v / max) * (height - p * 2);
        return (
          <g key={labels[i]}>
            <rect x={bx} y={by} width={barW} height={height - p - by} fill={color} rx="2" />
            <text x={bx + barW / 2} y={by - 3} textAnchor="middle" fill={textColor} fontSize="8" fontWeight="600">
              {v}K
            </text>
            <text className="tick" x={bx + barW / 2} y={height - 5} textAnchor="middle">
              {labels[i]}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

export function ExportDonutChart({
  data,
  centerValue,
  centerLabel,
}: {
  data: DonutDatum[];
  centerValue: string;
  centerLabel: string[];
}) {
  const cx = 75;
  const cy = 75;
  const r = 48;
  const sw = 16;
  let cum = 0;

  const slices = data.map((d) => {
    const f = d.pct / 100;
    const sa = cum * 2 * Math.PI - Math.PI / 2;
    cum += f;
    const ea = cum * 2 * Math.PI - Math.PI / 2;
    const x1 = cx + r * Math.cos(sa);
    const y1 = cy + r * Math.sin(sa);
    const x2 = cx + r * Math.cos(ea);
    const y2 = cy + r * Math.sin(ea);
    const largeArc = f > 0.5 ? 1 : 0;
    return (
      <path
        key={d.label}
        d={`M ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2}`}
        fill="none"
        stroke={d.color}
        strokeWidth={sw}
      />
    );
  });

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
      <svg width="180" height="150" viewBox="0 0 180 150">
        <circle cx={cx} cy={cy} r={r} fill="none" stroke="#F1F5F9" strokeWidth={sw} />
        {slices}
        {centerLabel.map((line, index) => (
          <text
            key={line}
            x={cx}
            y={cy - 6 + index * 10}
            textAnchor="middle"
            fontSize="7"
            fill="#94A3B8"
            fontFamily="Inter"
            fontWeight="500"
          >
            {line}
          </text>
        ))}
        <text x={cx} y={cy + 18} textAnchor="middle" fontSize="16" fontWeight="700" fill="#1E3A5F" fontFamily="Inter">
          {centerValue}
        </text>
      </svg>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 12px", justifyContent: "center", marginTop: 4, fontSize: 9.5, color: "#64748B" }}>
        {data.map((d) => (
          <span key={d.label}>
            {d.label} <b style={{ color: "#1E3A5F" }}>{d.value}</b>
          </span>
        ))}
      </div>
    </div>
  );
}

function renderDonutCallout({
  cx,
  cy,
  midAngle,
  outerRadius,
  percent,
  name,
  value,
}: {
  cx?: number;
  cy?: number;
  midAngle?: number;
  outerRadius?: number;
  percent?: number;
  name?: string;
  value?: string;
}) {
  const RADIAN = Math.PI / 180;
  const angle = midAngle ?? 0;
  const radius = outerRadius ?? 0;
  const centerX = cx ?? 0;
  const centerY = cy ?? 0;
  const sx = centerX + (radius - 4) * Math.cos(-angle * RADIAN);
  const sy = centerY + (radius - 4) * Math.sin(-angle * RADIAN);
  const mx = centerX + (radius + 12) * Math.cos(-angle * RADIAN);
  const my = centerY + (radius + 12) * Math.sin(-angle * RADIAN);
  const ex = mx + (Math.cos(-angle * RADIAN) >= 0 ? 28 : -28);
  const ey = my;
  const textAnchor = ex > centerX ? "start" : "end";

  return (
    <g>
      <path d={`M${sx},${sy}L${mx},${my}L${ex},${ey}`} stroke="#2f4357" strokeWidth={1.6} fill="none" />
      <text x={ex + (textAnchor === "start" ? 5 : -5)} y={ey - 8} textAnchor={textAnchor} fontSize="13" fill="#5f778e">
        {name}
      </text>
      <text x={ex + (textAnchor === "start" ? 5 : -5)} y={ey + 14} textAnchor={textAnchor} fontSize="17" fill="#2f4357" fontWeight="500">
        {value ?? `${Math.round((percent ?? 0) * 100)}%`}
      </text>
    </g>
  );
}

export function ExportLabeledDonutChart({
  data,
  centerValue,
  height = 290,
}: {
  data: DonutDatum[];
  centerValue?: string;
  height?: number;
}) {
  const computedCenterValue = centerValue ?? formatCompactAmount(data.reduce((sum, item) => sum + parseCompactAmount(item.value), 0));

  return (
    <div className="exportLabeledDonut" style={{ height }}>
      <ResponsiveContainer width="100%" height={height}>
        <PieChart margin={{ top: 18, right: 56, bottom: 18, left: 56 }}>
          <Pie
            data={data}
            dataKey="pct"
            nameKey="label"
            cx="50%"
            cy="56%"
            innerRadius="48%"
            outerRadius="72%"
            stroke="#ffffff"
            strokeWidth={3}
            labelLine={false}
            label={(props) =>
              renderDonutCallout({
                cx: props.cx,
                cy: props.cy,
                midAngle: props.midAngle,
                outerRadius: props.outerRadius,
                percent: props.percent,
                name: props.name,
                value: (props.payload as DonutDatum).value,
              })
            }
          >
            {data.map((entry) => (
              <Cell key={entry.label} fill={entry.color} />
            ))}
          </Pie>
          <text x="50%" y="56%" textAnchor="middle" dominantBaseline="middle" fontSize="34" fontWeight="500" fill="#2c3f52">
            {computedCenterValue}
          </text>
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
}

export function ExportBubbleChart({
  data,
  height = 260,
}: {
  data: BubbleDatum[];
  height?: number;
}) {
  if (!data.length) {
    return <div className="exportChartEmpty">No chart data available.</div>;
  }

  return (
    <div className="exportBubbleChart" style={{ height }}>
      <ResponsiveContainer width="100%" height={height}>
        <ScatterChart margin={{ top: 20, right: 18, bottom: 16, left: 16 }}>
          <CartesianGrid stroke="#d5e6f8" strokeDasharray="0" />
          <XAxis type="number" dataKey="x" domain={[0, 100]} tick={false} axisLine={false} tickLine={false} />
          <YAxis type="number" dataKey="y" domain={[0, 100]} tick={false} axisLine={false} tickLine={false} />
          <ZAxis type="number" dataKey="size" range={[1800, 16000]} />
          <Tooltip content={<BubbleTooltip />} cursor={false} />
          <Scatter data={data} shape={<BubbleShape />} />
        </ScatterChart>
      </ResponsiveContainer>
    </div>
  );
}

export function ExportFunnelChart({
  data,
  height = 250,
  leftHeader,
  rightHeader,
}: {
  data: FunnelDatum[];
  height?: number;
  leftHeader?: string;
  rightHeader?: string;
}) {
  if (!data.length) {
    return <div className="exportChartEmpty">No chart data available.</div>;
  }

  const fills = ["#b6ebf5", "#9ee2ee", "#7ad5e6", "#62c9dd"];
  const prepared = data.map((item, index) => ({
    ...item,
    value: item.width,
    fill: item.fill ?? fills[index % fills.length],
  }));

  return (
    <div className="exportFunnelLayout" style={{ minHeight: height }}>
      <div className="exportFunnelCanvas">
        <ResponsiveContainer width="100%" height={height}>
          <FunnelChart>
            <Tooltip content={<FunnelTooltip />} cursor={false} />
            <Funnel dataKey="value" data={prepared} isAnimationActive={false}>
              <LabelList content={<FunnelCenterLabel />} />
              {prepared.map((item) => (
                <Cell key={item.label} fill={item.fill} stroke={item.fill} />
              ))}
            </Funnel>
          </FunnelChart>
        </ResponsiveContainer>
      </div>

      <div className="exportFunnelMeta">
        {leftHeader || rightHeader ? (
          <div className="exportFunnelMetaHead">
            <span>{leftHeader ?? ""}</span>
            <span>{rightHeader ?? ""}</span>
          </div>
        ) : null}

        {prepared.map((item) => (
          <div key={item.label} className="exportFunnelMetaRow">
            <div className="exportFunnelMetaMain">
              <strong>
                {item.label} · {item.count}
              </strong>
              <div className="exportFunnelMetaNotes">
                <span>{item.leftNote}</span>
                <span>{item.rightNote}</span>
              </div>
            </div>
            <strong className="exportFunnelRevenue">{item.revenue}</strong>
          </div>
        ))}
      </div>
    </div>
  );
}

export function ExportSankeyChart({
  left,
  right,
}: {
  left: { acquire: string; build: string; contain: string };
  right: { acquire: string; build: string; contain: string };
}) {
  const nodeMeta = [
    { key: "acquire", label: "Acquire", color: "#2563EB", group: "left" as const },
    { key: "build", label: "Build", color: "#22C55E", group: "left" as const },
    { key: "contain", label: "Contain", color: "#F97316", group: "left" as const },
    { key: "acquire", label: "Acquire", color: "#2563EB", group: "right" as const },
    { key: "build", label: "Build", color: "#22C55E", group: "right" as const },
    { key: "contain", label: "Contain", color: "#F97316", group: "right" as const },
  ];

  const leftValues = [parseCompactAmount(left.acquire), parseCompactAmount(left.build), parseCompactAmount(left.contain)];
  const ratios = [
    [0.68, 0.22, 0.1],
    [0.18, 0.62, 0.2],
    [0.08, 0.26, 0.66],
  ];

  const links = leftValues.flatMap((value, rowIndex) =>
    ratios[rowIndex].map((ratio, columnIndex) => {
      const amount = Math.max(0, Math.round(value * ratio));
      return {
        source: rowIndex,
        target: columnIndex + 3,
        value: amount,
        sourceLabel: nodeMeta[rowIndex].label,
        targetLabel: nodeMeta[columnIndex + 3].label,
        color: nodeMeta[rowIndex].color,
      };
    }),
  );

  const nodes = nodeMeta.map((item, index) => ({
    name: `${item.label} ${item.group === "left" ? [left.acquire, left.build, left.contain][index] : [right.acquire, right.build, right.contain][index - 3]}`,
    label: item.label,
    valueLabel: item.group === "left" ? [left.acquire, left.build, left.contain][index] : [right.acquire, right.build, right.contain][index - 3],
    color: item.color,
    group: item.group,
  }));

  const SankeyNode = (props: any) => {
    const { x, y, width, height, payload } = props;
    if (!payload) {
      return null;
    }

    const alignRight = payload.group === "right";
    const labelX = alignRight ? x - 8 : x + width + 8;
    const labelAnchor = alignRight ? "end" : "start";

    return (
      <g>
        <rect x={x} y={y} width={width} height={height} rx={4} fill={payload.color} opacity="0.88" />
        <text x={labelX} y={y + height / 2 - 4} textAnchor={labelAnchor} fill="#4b6177" fontSize="11" fontWeight="700">
          {payload.label}
        </text>
        <text x={labelX} y={y + height / 2 + 11} textAnchor={labelAnchor} fill={payload.color} fontSize="11" fontWeight="700">
          {payload.valueLabel}
        </text>
      </g>
    );
  };

  const SankeyLink = (props: any) => {
    const { sourceX, targetX, sourceY, targetY, sourceControlX, targetControlX, linkWidth, payload } = props;
    const path = `
      M${sourceX},${sourceY - linkWidth / 2}
      C${sourceControlX},${sourceY - linkWidth / 2} ${targetControlX},${targetY - linkWidth / 2} ${targetX},${targetY - linkWidth / 2}
      L${targetX},${targetY + linkWidth / 2}
      C${targetControlX},${targetY + linkWidth / 2} ${sourceControlX},${sourceY + linkWidth / 2} ${sourceX},${sourceY + linkWidth / 2}
      Z
    `;

    return <path d={path} fill={payload.color} opacity="0.22" stroke="none" />;
  };

  return (
    <div className="exportSankeyWrap">
      <ResponsiveContainer width="100%" height="100%">
        <Sankey
          data={{ nodes, links }}
          nodePadding={18}
          nodeWidth={12}
          margin={{ top: 6, right: 44, bottom: 4, left: 44 }}
          link={<SankeyLink />}
          node={<SankeyNode />}
          iterations={64}
        >
          <Tooltip content={<SankeyTooltip />} cursor={false} />
        </Sankey>
      </ResponsiveContainer>
    </div>
  );
}

export function ExportBubbleSegments({
  segments,
}: {
  segments: Array<{ label: string; value: number; color: string; x: number; y: number; size: number }>;
}) {
  return (
    <svg viewBox="0 0 280 180" style={{ width: "100%", height: 180 }}>
      {segments.map((segment) => (
        <g key={segment.label}>
          <circle
            cx={segment.x * 2.2}
            cy={180 - segment.y * 1.8}
            r={Math.max(12, segment.size / 2.6)}
            fill={segment.color}
            opacity="0.28"
            stroke={segment.color}
            strokeWidth="1.5"
          />
          <text
            x={segment.x * 2.2}
            y={183 - segment.y * 1.8}
            textAnchor="middle"
            fontSize="18"
            fontWeight="700"
            fill={segment.color}
          >
            {segment.value}%
          </text>
        </g>
      ))}
    </svg>
  );
}

export function ExportHeatmap({
  values,
  columns,
  rows,
}: {
  values: number[][];
  columns: string[];
  rows: string[];
}) {
  return (
    <div className="campaignHeatmap">
      <div className="campaignHeatHeaderSpacer" />
      {columns.map((column) => (
        <div key={column} className="campaignHeatHeader">
          {column}
        </div>
      ))}
      {rows.map((row, rowIndex) => (
        <div key={row} className="campaignHeatRow">
          <div className="campaignHeatTime">{row.replace(".", ":")}</div>
          {columns.map((column, columnIndex) => (
            <div
              key={`${row}-${column}`}
              className="campaignHeatCell"
              data-val={`${Math.round(values[rowIndex][columnIndex] * 100)}%`}
              style={{ background: `rgba(33, 173, 214, ${Math.max(values[rowIndex][columnIndex], 0.18)})` }}
              title={`${column} at ${row.replace(".", ":")}: ${Math.round(values[rowIndex][columnIndex] * 100)}%`}
            />
          ))}
        </div>
      ))}
    </div>
  );
}

export function ExportEntitiesSummary({
  summary,
  series,
  chartHeight = 130,
}: {
  summary: { entities: string; enrolled: string; revenue: string };
  series: Array<{ name: string; bar: number; line: number }>;
  chartHeight?: number;
}) {
  const chartTop = 16;
  const chartBottom = 24;
  const labelY = chartHeight - 5;
  const availableHeight = chartHeight - chartTop - chartBottom;
  const barMax = Math.max(...series.map((item) => item.bar), 1);
  const lineMax = Math.max(...series.map((item) => item.line), 1);
  const points = series.map((item, index) => {
    const x = 40 + (index / Math.max(series.length - 1, 1)) * 180;
    const y = chartHeight - chartBottom - (item.line / lineMax) * availableHeight;
    return [x, y] as const;
  });

  return (
    <>
      <div style={{ display: "flex", gap: 14, fontSize: 10, marginBottom: 8 }}>
        <div><b style={{ color: "#1E3A5F", fontSize: 16 }}>{summary.entities}</b><br /><span style={{ color: "#64748B" }}>Entities active</span></div>
        <div><b style={{ color: "#1E3A5F", fontSize: 16 }}>{summary.enrolled}</b><br /><span style={{ color: "#64748B" }}>Total enrolled</span></div>
        <div><b style={{ color: "#22C55E", fontSize: 16 }}>{summary.revenue}</b><br /><span style={{ color: "#64748B" }}>Total Revenue</span></div>
      </div>
      <svg viewBox={`0 0 280 ${chartHeight}`} style={{ width: "100%", height: chartHeight }} preserveAspectRatio="none">
        {[0, 1, 2, 3].map((i) => (
          <line key={i} className="grid-line" x1="20" y1={chartTop + (i * availableHeight) / 3} x2="260" y2={chartTop + (i * availableHeight) / 3} />
        ))}
        {series.map((item, index) => {
          const x = 40 + (index / Math.max(series.length - 1, 1)) * 180;
          const h = (item.bar / barMax) * availableHeight;
          return (
            <g key={item.name}>
              <rect x={x - 10} y={chartHeight - chartBottom - h} width="20" height={h} fill="#BFDBFE" rx="2" />
              <text x={x} y={chartHeight - chartBottom - h - 4} textAnchor="middle" fontSize="8" fill="#22C55E" fontWeight="600">{item.bar}K</text>
              <text x={x} y={labelY} textAnchor="middle" fontSize="8" fill="#64748B">{item.name}</text>
            </g>
          );
        })}
        <path
          d={points.map(([x, y], index) => `${index ? "L" : "M"} ${x} ${y}`).join(" ")}
          fill="none"
          stroke="#22C55E"
          strokeWidth="2"
        />
        {points.map(([x, y], index) => (
          <circle key={index} cx={x} cy={y} r="3" fill="#22C55E" />
        ))}
      </svg>
    </>
  );
}
